class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        count = 0
        for i in range(len(s)):
            for j in range(i, len(s)):
                if 'a' in s[i:j+1] and 'b' in s[i:j+1] and 'c' in s[i:j+1]:
                    count += 1
        return count
